const inputBody = $json || {}; 
const binaryData = $input.first().binary || {}; 

const script = inputBody.script || inputBody.scriptContent || inputBody.story_text || '';
const sellingPoints = inputBody.selling_points || []; // 允许为空数组
const contentType = inputBody.content_type || 'ugc带货';
const aspectRatio = inputBody.aspectRatio || inputBody.aspect_ratio || '9:16';
const styleMode = inputBody.style_mode || 'anime';

if (!script) throw new Error('缺少剧本 (script)');

// 🔍 修改点：只校验产品图，不再强制要求 selling_points
if (contentType === '产品卖点展示' && !binaryData.product_data) {
  throw new Error('内容类型为“产品卖点展示”时，必须提供 productImageUrl (产品外观图)');
}

const modelB64 = binaryData.model_data?.data;
const productB64 = binaryData.product_data?.data || ''; 

if (!modelB64) throw new Error('未能获取到基础参考图的 Base64 数据');

return {
  json: {
    ...inputBody,
    story_text: script,
    selling_points: sellingPoints, 
    model_image_b64: modelB64, 
    product_image_b64: productB64, 
    model_mime_type: inputBody.modelMimeType || 'image/jpeg',
    product_mime_type: inputBody.productMimeType || 'image/jpeg',
    content_type: contentType,
    aspectRatio,
    style_mode: styleMode,
    taskId: inputBody.taskId || inputBody.task_id || inputBody.record_id || 'unknown_task'
  }
};

function s(v){ return v == null ? '' : String(v); }
function stripDataPrefix(b64){ return s(b64).trim().replace(/^data:.*;base64,/, '').trim(); }

const j = $json || {};
const content_type = s(j.content_type).trim() || 'ugc带货';
const story_text = s(j.story_text).trim();
const selling_points = j.selling_points || []; 
const style_mode = s(j.style_mode).trim() || 'anime';

const model_image_b64 = stripDataPrefix(j.model_image_b64);
const product_image_b64 = stripDataPrefix(j.product_image_b64);

if (!story_text) throw new Error('缺少剧本 story_text');
if (!model_image_b64) throw new Error('缺少基础参考图 model_image_b64');

// 🔍 判断用户是否传了卖点
const hasUserSellingPoints = selling_points.length > 0;

const baseRules = [
  'You are a senior storyboard director and cinematic video prompt engineer.',
  'Your job is to convert the script, selling points (if provided), and reference image(s) into a 9-shot storyboard plan for a single 3x3 storyboard grid image.',
  'You must preserve identity consistency, outfit consistency, product appearance consistency (if provided), and scene logic consistency.',
  'shots must be exactly 9 items.',
  'Each shot must be visually distinct but remain coherent as one continuous story.',
  'Do not output vague prompts. Be concrete and visual.',
  'No text overlays, no subtitles, no watermark, no UI.'
].join(' ');

// 🔍 针对“产品卖点展示”动态生成规则
const sellingPointRule = hasUserSellingPoints 
  ? 'You MUST integrate the provided `selling_points` list as the core storybeat.' 
  : 'Analyze the Product Image and Script to INFER 3-5 core functional selling points. List them in `selling_points_focus`, and use them as the core storybeat.';

const typeRulesMap = {
  'ugc带货': 'UGC commercial style narrative. The same person naturally interacts with the product across the 9 shots.',
  '产品展示': 'Product showcase style. The product is always the hero. Use different framings, angles, and hero beauty shots.',
  '剧情故事': 'Narrative storytelling style. Characters and props must remain continuous.',
  '产品卖点展示': `Focus on DEMONSTRATING functional selling points (USP). ${sellingPointRule} Visually demonstrate the benefit of each selling point in action.`
};

const styleRulesMap = {
  anime: 'Preserve original anime/illustration style. Maintain cel shading, clean lineart. DO NOT make it photorealistic.',
  realistic: 'Preserve original realistic/live-action style. Maintain cinematic lighting, realistic anatomy. DO NOT cartoonize.',
  auto: 'Infer the visual style from the reference image, then preserve it strictly.'
};

const typeRules = typeRulesMap[content_type] || typeRulesMap['ugc带货'];
const styleRules = styleRulesMap[style_mode] || styleRulesMap['anime'];

const outputSchema = {
  content_type: content_type,
  style_mode: style_mode,
  // 🔍 让 AI 把最终使用的卖点（用户提供的，或自己提炼的）回传给我们
  selling_points_focus: contentType === '产品卖点展示' ? ['Selling Point 1', 'Selling Point 2'] : [], 
  visual_anchor: {
    subject_identity: 'Specify how to anchor the person identity',
    outfit_anchor: 'Specify how to anchor the outfit and accessories',
    product_anchor: product_image_b64 ? 'Specify product appearance from Product Image' : 'Infer product from script/reference',
    scene_anchor: 'Specify environment logic'
  },
  global_style: 'No text, no UI...',
  negative_prompts: ['text overlay', 'watermark', 'frame border'],
  shots: [
    {
      shot_index: 1,
      focus_selling_point: contentType === '产品卖点展示' ? 'Specify which selling point is demonstrated here' : 'N/A', 
      title: 'shot title',
      story_beat: 'what this beat does in the story',
      subject: 'main subject',
      scene: 'where it happens',
      camera_shot: 'composition / size / angle',
      motion_hint: 'dynamics for later video expansion',
      prompt_text: 'detailed visual prompt.' 
    }
  ]
};

// 🔍 动态组装卖点输入文本
let sellingPointsInputText = 'N/A';
if (content_type === '产品卖点展示') {
  sellingPointsInputText = hasUserSellingPoints 
    ? JSON.stringify(selling_points, null, 2) 
    : 'NOT PROVIDED. Please infer them from the Product Image and Script, and output them in `selling_points_focus`.';
}

const instruction = `You are a senior cinematic video prompt engineer.

Input fields:
- script: basic story description
- selling_points: product unique selling points
- content_type: content narrative type (${Object.keys(typeRulesMap).join('|')})
- style_mode: visual style mode (${Object.keys(styleRulesMap).join('|')})

Core Goals:
${baseRules}

Content type rules:
${typeRules}

Style preservation rules:
${styleRules}

Hard constraints:
1. shots must be exactly 9 items.
2. prompt_text must be detailed and visual.
3. If content_type is '产品卖点展示', distribute the key selling_points logically across the 9 shots.

[INPUT DATA]
Script:
${story_text}

Selling Points:
${sellingPointsInputText}

Return a JSON object following this structure exactly:
${JSON.stringify(outputSchema, null, 2)}`;

const promptParts = [
  { text: instruction },
  {
    inline_data: {
      mime_type: s(j.model_mime_type).trim() || 'image/jpeg',
      data: model_image_b64
    }
  }
];

if (product_image_b64) {
  promptParts.push({
    inline_data: {
      mime_type: s(j.product_mime_type).trim() || 'image/jpeg',
      data: product_image_b64
    }
  });
}

const image_storyboard_body = {
  contents: [
    {
      role: 'user',
      parts: promptParts
    }
  ],
  generationConfig: {
    temperature: 0.5,
    responseMimeType: 'application/json'
  }
};

return {
  json: {
    ...j,
    image_storyboard_body
  }
};

function unwrapRoot(x) {
  if (x && typeof x === 'object' && x.body && typeof x.body === 'object') return x.body;
  return x;
}

function extractFirstJsonObject(s) {
  if (!s) return '';
  const cleaned = String(s).replace(/```json\s*/gi, '').replace(/```/g, '').trim();
  const start = cleaned.indexOf('{');
  if (start < 0) return '';
  let depth = 0;
  let inString = false;
  let escaped = false;
  for (let i = start; i < cleaned.length; i++) {
    const ch = cleaned[i];
    if (escaped) {
      escaped = false;
      continue;
    }
    if (ch === '\\') {
      escaped = true;
      continue;
    }
    if (ch === '"') {
      inString = !inString;
      continue;
    }
    if (!inString) {
      if (ch === '{') depth++;
      if (ch === '}') depth--;
      if (depth === 0) return cleaned.slice(start, i + 1).trim();
    }
  }
  return '';
}

function extractText(root) {
  const parts = root?.candidates?.[0]?.content?.parts;
  if (!Array.isArray(parts) || parts.length === 0) return '';
  const direct = parts.find(p => typeof p?.text === 'string' && p.text.trim().startsWith('{'));
  if (direct) return direct.text.trim();
  const all = parts.map(p => typeof p?.text === 'string' ? p.text : '').filter(Boolean).join('\n');
  return extractFirstJsonObject(all);
}

const raw = $json || {};
const root = unwrapRoot(raw);
const text = extractText(root);
if (!text) throw new Error('第一阶段九宫格分镜 agent 未返回可解析 JSON');

let plan;
try {
  plan = JSON.parse(text);
} catch (e) {
  throw new Error('第一阶段九宫格分镜 JSON 解析失败：' + e.message + '\n原文前500字：' + String(text).slice(0, 500));
}

const shots = Array.isArray(plan?.shots) ? plan.shots : [];
if (shots.length !== 9) {
  throw new Error('第一阶段九宫格分镜 shots 必须刚好 9 个；实际=' + shots.length);
}

const content_type = String(plan?.content_type || 'ugc带货');
const style_mode = String(plan?.style_mode || $('Prepare Gemini Data').first().json.style_mode || 'anime');

const hardCommon = `Create ONE single image. It must be a full-bleed 3x3 grid (nine panels) that fills the entire canvas with NO margins, NO borders, NO frames, NO gutters, NO gridlines, NO separators.\nNo visible text of any kind: no captions, no labels, no numbers, no watermark, no UI.\nPreserve identity consistency, outfit consistency, prop consistency, and scene logic consistency across all panels.\n`;

const styleLockMap = {
  anime: `Preserve the original anime / illustration style from the reference image. Maintain 2D anime aesthetic, cel shading, clean lineart, stylized facial design, illustrated texture, non-photorealistic rendering. Do NOT convert any character into a real human. Do NOT use live-action look.`,
  realistic: `Preserve the original realistic / live-action style from the reference image. Maintain realistic skin texture, cinematic lighting, realistic anatomy, real-world material rendering. Do NOT convert into anime or cartoon look.`,
  auto: `First infer the original style from the reference image, then preserve it strictly. If anime, keep anime and do not make it photorealistic. If realistic, keep realistic and do not cartoonize it.`
};

const hardByType = {
  'ugc带货': `Preserve EXACTLY the same number of people as the reference image across all panels. Do NOT add or remove any person. Keep the SAME set of people across all panels. Keep EACH person's identity consistent. Keep the SAME product identity across all panels. Keep a consistent environment and lighting logic across all panels.`,
  '产品展示': `Keep the SAME product identity across all panels. Product is the hero. Show different angles, macro details, usage steps, and hero shots while preserving original style.`,
  '剧情故事': `If the reference image contains multiple people, preserve EXACTLY the same number of people. Characters must stay consistent when they re-appear. Locations MAY change between panels if the story requires it, but continuity must be coherent.`
};

const hardLayout = [hardCommon, styleLockMap[style_mode] || styleLockMap['anime'], hardByType[content_type] || hardByType['ugc带货']].join('\n');

const panels = shots.map((s, i) => {
  const p = String(s?.prompt_text || '').trim();
  if (!p) throw new Error('第 ' + (i + 1) + ' 个 shot 的 prompt_text 为空');
  return `Panel ${i + 1} (left-to-right, top-to-bottom): ${p}`;
}).join('\n\n');

const neg = Array.isArray(plan?.negative_prompts) ? plan.negative_prompts.join(', ') : '';
const negBlock = neg ? `\nNegative: ${neg}` : '';

const base = $('Prepare Gemini Data').first().json || {};

return {
  json: {
    ...base,
    style_mode,
    image_storyboard_json: plan,
    grid_prompt: `${hardLayout}\n\n${panels}${negBlock}`
  }
};

function s(v){ return v == null ? '' : String(v); }
function stripDataPrefix(b64){ return s(b64).trim().replace(/^data:.*;base64,/, '').trim(); }

const j = $json || {};
const img_b64 = stripDataPrefix(j.person_image_b64);
const img_mime = s(j.person_mime_type).trim() || 'image/jpeg';
const promptText = s(j.grid_prompt).trim();
const aspectRatio = s(j.aspectRatio).trim() || '9:16';
const styleMode = s(j.style_mode).trim() || 'anime';

if (!img_b64) throw new Error('缺少 person_image_b64');
if (!promptText) throw new Error('缺少 grid_prompt');

const CONSISTENCY_LOCK = `ABSOLUTE CONSISTENCY LOCK (must follow):\n- Preserve EXACTLY the same number of people as the reference image. Do NOT add or remove any person.\n- Keep EXACTLY the same set of identities as the reference image (for EACH person): same face structure / anime face design, eyes, nose, lips, skin tone, hairstyle, hair color, makeup.\n- Keep EXACTLY the same outfit and accessories as the reference image.\n- Keep EXACTLY the same core character design and props from the reference image.\n- Do NOT swap hands, do NOT mirror / flip the image.\n- No text, no subtitles, no watermark, no UI, no borders, no frames, no gridlines, no separators.`.trim();

const STYLE_LOCK_MAP = {
  anime: `STYLE LOCK (anime):\n- Preserve the original anime / illustration style from the reference image.\n- Maintain 2D illustrated look, cel shading, clean lineart, stylized facial design, anime proportions, illustrated texture.\n- Keep the same anime character design language, color rendering style, and drawing texture.\n- Do NOT convert into real human or live-action style.\n- Do NOT make the face photorealistic.`,
  realistic: `STYLE LOCK (realistic):\n- Preserve the original realistic / live-action style from the reference image.\n- Maintain realistic skin texture, natural human anatomy, cinematic lighting, realistic materials.\n- Do NOT convert into anime or cartoon style.`,
  auto: `STYLE LOCK (auto):\n- First infer the original style from the reference image, then preserve it strictly.\n- If anime / illustration, keep anime / illustration and do NOT make it photorealistic.\n- If realistic, keep realistic and do NOT cartoonize it.`
};

const finalPrompt = `${CONSISTENCY_LOCK}\n\n${STYLE_LOCK_MAP[styleMode] || STYLE_LOCK_MAP['anime']}\n\n${promptText}`;

const request_body = {
  contents: [
    {
      role: 'user',
      parts: [
        { text: finalPrompt },
        {
          inline_data: {
            mime_type: img_mime,
            data: img_b64
          }
        }
      ]
    }
  ],
  generationConfig: {
    responseModalities: ['IMAGE'],
    imageConfig: {
      aspectRatio,
      imageSize: '4K'
    }
  }
};

return {
  json: {
    ...j,
    final_grid_prompt: finalPrompt,
    request_body
  }
};

function unwrapRoot(x) {
  if (x && typeof x === 'object' && x.body && typeof x.body === 'object') return x.body;
  return x;
}

function getByPath(obj, path) {
  try {
    return path.split('.').reduce((acc, k) => (acc == null ? undefined : acc[k]), obj);
  } catch {
    return undefined;
  }
}

function findInlineImageParts(root) {
  const candidates = root?.candidates;
  if (!Array.isArray(candidates) || !candidates.length) return [];
  const parts = candidates?.[0]?.content?.parts;
  if (!Array.isArray(parts)) return [];
  const imgs = [];
  for (const p of parts) {
    const inline = p?.inline_data || p?.inlineData;
    if (inline?.data) {
      imgs.push({ b64: inline.data, mimeType: inline.mime_type || inline.mimeType || 'image/png' });
      continue;
    }
    const fd = p?.fileData;
    if (fd?.fileUri) {
      imgs.push({ fileUri: fd.fileUri, mimeType: fd.mimeType || 'image/png' });
    }
  }
  return imgs;
}

function stripDataPrefix(b64) {
  return String(b64 || '').replace(/^data:.*;base64,/, '').trim();
}

const raw = $json || {};
const root = unwrapRoot(raw);
let imgs = findInlineImageParts(root);

if (!imgs.length) {
  const maybe = getByPath(root, 'image.data') || getByPath(root, 'data.image') || getByPath(root, 'output.image') || getByPath(root, 'output.data') || null;
  if (maybe && typeof maybe === 'string') imgs = [{ b64: maybe, mimeType: 'image/png' }];
}

if (!imgs.length) throw new Error('没有在返回体中找到图片数据（inline_data / inlineData）');

const first = imgs[0];
if (first.fileUri && !first.b64) {
  throw new Error(`返回的是 fileUri（${first.fileUri}）而不是 base64，需要额外下载。当前流程未处理 fileUri 模式。`);
}

const mimeType = first.mimeType || 'image/png';
const ext = mimeType.includes('jpeg') || mimeType.includes('jpg') ? 'jpg' : 'png';
const b64 = stripDataPrefix(first.b64);
if (!b64) throw new Error('图片 base64 为空');

const base = $('组装九宫格生图请求体').first().json || {};

return {
  json: {
    ...base,
    mimeType,
    generated_grid_b64: b64,
    generated_grid_mime_type: mimeType,
    fileName: `storyboard_grid.${ext}`
  },
  binary: {
    data: {
      data: b64,
      mimeType,
      fileName: `storyboard_grid.${ext}`
    }
  }
};

function s(v){ return v == null ? '' : String(v); }
function stripDataPrefix(b64){ return s(b64).trim().replace(/^data:.*;base64,/, '').trim(); }

const base = $('生成上传文件名').first().json || {};
const imageStoryboard = base.image_storyboard_json || {};
const shots = Array.isArray(imageStoryboard?.shots) ? imageStoryboard.shots : [];
if (shots.length !== 9) throw new Error('第二阶段前校验失败：image_storyboard_json.shots 不是 9 个');

const gridB64 = stripDataPrefix(base.generated_grid_b64);
const gridMime = s(base.generated_grid_mime_type).trim() || 'image/png';
const styleMode = s(base.style_mode).trim() || 'anime';
if (!gridB64) throw new Error('缺少生成后的九宫格图片 base64');

const storyText = s(base.story_text).trim();
const contentType = s(base.content_type).trim() || 'ugc带货';

