Task:
The uploaded image is a 3x3 storyboard grid image. Based on this generated storyboard image and the structured storyboard JSON, expand each of the 9 storyboard shots into a highly detailed 8-second video prompt.

Style preservation rule:
${styleRulesMap[styleMode] || styleRulesMap['anime']}

Hard requirements:
1. Do NOT rewrite the story structure.
2. Keep the same person identity, outfit, accessories, product identity, and scene logic from the storyboard image and storyboard JSON.
3. Each shot duration is EXACTLY 8 seconds.
4. For EACH shot output these fields:
   - shot_index
   - title
   - story_beat
   - subject
   - scene
   - emotion
   - camera_shot
   - motion_hint
   - prompt_text
   - start_frame
   - action
   - end_frame
   - style
   - timeline (minimum 4 segments)
   - video_prompt
5. The final video_prompt must strictly use this structure:
   Start frame: ...
   Action: ...
   End frame: ...
   Style: ...
6. timeline must describe the exact 8-second evolution with time_range / visual / camera / environment.
7. Maintain subject consistency and scene consistency throughout.
8. Return JSON only. No markdown. No explanation.

Return schema example:
{
  "content_type": "${contentType}",
  "style_mode": "${styleMode}",
  "global_video_rules": {
    "duration_per_shot": 8,
    "subject_consistency": true,
    "scene_consistency": true,
    "style_anchor": "preserve original visual style from storyboard image"
  },
  "shots": [
    {
      "shot_index": 1,
      "title": "...",
      "story_beat": "...",
      "subject": "...",
      "scene": "...",
      "emotion": "...",
      "camera_shot": "...",
      "motion_hint": "...",
      "prompt_text": "...",
      "start_frame": "...",
      "action": "...",
      "end_frame": "...",
      "style": "...",
      "timeline": [
        {
          "time_range": "0.0-1.5s",
          "visual": "...",
          "camera": "...",
          "environment": "..."
        },
        {
          "time_range": "1.5-3.5s",
          "visual": "...",
          "camera": "...",
          "environment": "..."
        },
        {
          "time_range": "3.5-6.0s",
          "visual": "...",
          "camera": "...",
          "environment": "..."
        },
        {
          "time_range": "6.0-8.0s",
          "visual": "...",
          "camera": "...",
          "environment": "..."
        }
      ],
      "video_prompt": "Start frame: ... Action: ... End frame: ... Style: ..."
    }
  ]
}`;

const video_prompt_body = {
  contents: [
    {
      role: 'user',
      parts: [
        { text: instruction + '

Story text:
' + storyText + '

Structured storyboard JSON:
' + JSON.stringify(imageStoryboard, null, 2) },
        { inline_data: { mime_type: gridMime, data: gridB64 } }
      ]
    }
  ],
  generationConfig: {
    temperature: 0.5,
    responseMimeType: 'application/json'
  }
};

return {
  json: {
    ...base,
    video_prompt_body
  }
};

function unwrapRoot(x) {
  if (x && typeof x === 'object' && x.body && typeof x.body === 'object') return x.body;
  return x;
}

function extractFirstJsonObject(s) {
  if (!s) return '';
  const cleaned = String(s).replace(/```json\s*/gi, '').replace(/```/g, '').trim();
  const start = cleaned.indexOf('{');
  if (start < 0) return '';
  let depth = 0;
  let inString = false;
  let escaped = false;
  for (let i = start; i < cleaned.length; i++) {
    const ch = cleaned[i];
    if (escaped) {
      escaped = false;
      continue;
    }
    if (ch === '\\') {
      escaped = true;
      continue;
    }
    if (ch === '"') {
      inString = !inString;
      continue;
    }
    if (!inString) {
      if (ch === '{') depth++;
      if (ch === '}') depth--;
      if (depth === 0) return cleaned.slice(start, i + 1).trim();
    }
  }
  return '';
}

function extractText(root) {
  const parts = root?.candidates?.[0]?.content?.parts;
  if (!Array.isArray(parts) || parts.length === 0) return '';
  const direct = parts.find(p => typeof p?.text === 'string' && p.text.trim().startsWith('{'));
  if (direct) return direct.text.trim();
  const all = parts.map(p => typeof p?.text === 'string' ? p.text : '').filter(Boolean).join('\n');
  return extractFirstJsonObject(all);
}

const raw = $json || {};
const root = unwrapRoot(raw);
const text = extractText(root);
if (!text) throw new Error('第二阶段视频提示词 agent 未返回可解析 JSON');

let videoPlan;
try {
  videoPlan = JSON.parse(text);
} catch (e) {
  throw new Error('第二阶段视频提示词 JSON 解析失败：' + e.message + '\n原文前500字：' + String(text).slice(0, 500));
}

const shots = Array.isArray(videoPlan?.shots) ? videoPlan.shots : [];
if (shots.length !== 9) {
  throw new Error('第二阶段视频提示词 shots 必须刚好 9 个；实际=' + shots.length);
}

const base = $('组装视频提示词请求').first().json || {};

return {
  json: {
    taskId: base.taskId,
    style_mode: base.style_mode,
    storyboard_image_url: base.storyboard_image_url,
    image_storyboard_json: base.image_storyboard_json || {},
    video_storyboard_json: videoPlan,
    video_prompt_list: shots.map(s => ({
      shot_index: s.shot_index,
      title: s.title,
      video_prompt: s.video_prompt
    }))
  }
};

const taskId = $json.taskId || 'unknown_task';
const timestamp = Date.now();
const mimeType = $json.mimeType || 'image/png';
const ext = mimeType.includes('jpeg') || mimeType.includes('jpg') ? 'jpg' : 'png';

// OSS 配置
const folder = 'storyboard';
const fileName = `${taskId}_grid_${timestamp}.${ext}`;
const ossPath = `${folder}/${fileName}`; // OSS 插件需要的路径

return {
  json: {
    ...($json || {}),
    fileName,
    ossPath,
    taskId
  },
  binary: {
    data: $input.item.binary.data
  }
};

const uploadItems = $input.all();
const preparedItems = $('准备上传参数').all();

return uploadItems.map((item, idx) => {
  const resp = item.json || {};
  const prepared = preparedItems[idx]?.json || {};

  const publicUrl = resp.url || resp.publicUrl || prepared.publicUrl || '';

  return {
    json: {
      ...prepared,
      ...resp,
      publicUrl
    }
  };
});

const inputBody = $('Webhook').item.json.body || {};
const modelUrl = inputBody.imageUrl || inputBody.referenceImage;
const productUrl = inputBody.productImageUrl; // 现在变成选填了

if (!modelUrl) {
  throw new Error('Missing imageUrl (必须提供基础参考图)');
}

// 动态构建下载任务
const promises = [
  this.helpers.httpRequest({ url: modelUrl, encoding: null, resolveWithFullResponse: true })
];

if (productUrl) {
  promises.push(
    this.helpers.httpRequest({ url: productUrl, encoding: null, resolveWithFullResponse: true })
  );
}

const results = await Promise.all(promises);

// 处理基础参考图
const modelRes = results[0];
const binary = {
  model_data: {
    data: modelRes.body.toString('base64'),
    mimeType: modelRes.headers['content-type'] || 'image/jpeg',
    fileName: 'model.png'
  }
};

// 如果有产品图，处理产品图
if (productUrl && results[1]) {
  const productRes = results[1];
  binary.product_data = {
    data: productRes.body.toString('base64'),
    mimeType: productRes.headers['content-type'] || 'image/jpeg',
    fileName: 'product.png'
  };
}

return {
  json: {
    ...inputBody,
    modelMimeType: binary.model_data.mimeType,
    productMimeType: binary.product_data?.mimeType || ''
  },
  binary
};
